import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Values in the Wild: Discovering and Analyzing Values in Real-World Language Model Interactions","description":"","frontmatter":{"title":"Values in the Wild: Discovering and Analyzing Values in Real-World Language Model Interactions","authors":"Saffron Huang, Esin Durmus, Miles McCain, Kunal Handa, Alex Tamkin, Jerry Hong, Michael Stern, Arushi Somani, Xiuruo Zhang, Deep Ganguli","published":"2025-04-21T00:00:00.000Z","source":"https://arxiv.org/abs/2504.15236"},"headers":[],"relativePath":"research/papers/2025-04-21-values-in-the-wild-claude-interactions-2504-15236.md","filePath":"research/papers/2025-04-21-values-in-the-wild-claude-interactions-2504-15236.md","lastUpdated":1779901665000}'),o={name:"research/papers/2025-04-21-values-in-the-wild-claude-interactions-2504-15236.md"};function i(s,t,l,d,u,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="values-in-the-wild-discovering-and-analyzing-values-in-real-world-language-model-interactions" tabindex="-1">Values in the Wild: Discovering and Analyzing Values in Real-World Language Model Interactions <a class="header-anchor" href="#values-in-the-wild-discovering-and-analyzing-values-in-real-world-language-model-interactions" aria-label="Permalink to &quot;Values in the Wild: Discovering and Analyzing Values in Real-World Language Model Interactions&quot;">​</a></h1><p><strong>Authors</strong>: Saffron Huang, Esin Durmus, Miles McCain, Kunal Handa, Alex Tamkin, Jerry Hong, Michael Stern, Arushi Somani, Xiuruo Zhang, Deep Ganguli (Anthropic) <strong>Published</strong>: April 21, 2025 <strong>Source</strong>: <a href="https://arxiv.org/abs/2504.15236" target="_blank" rel="noreferrer">https://arxiv.org/abs/2504.15236</a><strong>arXiv ID</strong>: 2504.15236 <strong>Categories</strong>: cs.CL, cs.AI <strong>Data</strong>: HuggingFace — Anthropic/values-in-the-wild</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>First large-scale empirical mapping of AI values &quot;in the wild.&quot; Using privacy-preserving Clio analysis of 700,000 anonymized Claude.ai conversations, the authors discover and taxonomize 3,307 distinct AI values and 2,483 human values. Claude expresses many practical and epistemic values, typically supports prosocial human values, and resists values like moral nihilism. Values are highly context-dependent.</p><hr><h2 id="dataset" tabindex="-1">Dataset <a class="header-anchor" href="#dataset" aria-label="Permalink to &quot;Dataset&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Total conversations analyzed</td><td>700,000 anonymized Claude.ai conversations</td></tr><tr><td>Period</td><td>February 18–25, 2025</td></tr><tr><td>Subjective conversations (used for analysis)</td><td>308,210 (44% of total)</td></tr><tr><td>Model composition</td><td>91% Claude 3.5 Sonnet</td></tr><tr><td>Human validation accuracy</td><td><strong>98.8%</strong></td></tr></tbody></table><hr><h2 id="key-findings-most-common-values" tabindex="-1">Key Findings: Most Common Values <a class="header-anchor" href="#key-findings-most-common-values" aria-label="Permalink to &quot;Key Findings: Most Common Values&quot;">​</a></h2><h3 id="top-ai-values-by-frequency" tabindex="-1">Top AI Values (by frequency) <a class="header-anchor" href="#top-ai-values-by-frequency" aria-label="Permalink to &quot;Top AI Values (by frequency)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>AI Value</th><th>Frequency</th></tr></thead><tbody><tr><td>1</td><td>Helpfulness</td><td>23.4%</td></tr><tr><td>2</td><td>Professionalism</td><td>22.9%</td></tr><tr><td>3</td><td>Transparency</td><td>17.4%</td></tr><tr><td>4</td><td>Clarity</td><td>16.6%</td></tr><tr><td>5</td><td>Thoroughness</td><td>14.3%</td></tr></tbody></table><h3 id="top-human-values-by-frequency" tabindex="-1">Top Human Values (by frequency) <a class="header-anchor" href="#top-human-values-by-frequency" aria-label="Permalink to &quot;Top Human Values (by frequency)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Human Value</th><th>Frequency</th></tr></thead><tbody><tr><td>1</td><td>Authenticity</td><td>3.8%</td></tr><tr><td>2</td><td>Efficiency</td><td>2.6%</td></tr><tr><td>3</td><td>Clarity</td><td>2.2%</td></tr><tr><td>4</td><td>Professionalism</td><td>1.5%</td></tr><tr><td>5</td><td>Directness</td><td>1.5%</td></tr></tbody></table><hr><h2 id="value-taxonomy-five-domains" tabindex="-1">Value Taxonomy: Five Domains <a class="header-anchor" href="#value-taxonomy-five-domains" aria-label="Permalink to &quot;Value Taxonomy: Five Domains&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Domain</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Practical values</strong></td><td>Service delivery, competence, helpfulness</td></tr><tr><td><strong>Epistemic values</strong></td><td>Knowledge, accuracy, historical accuracy</td></tr><tr><td><strong>Social values</strong></td><td>Relationships, community, mutual respect</td></tr><tr><td><strong>Protective values</strong></td><td>Safety, boundaries, harm prevention</td></tr><tr><td><strong>Personal values</strong></td><td>Growth, fulfillment, human agency</td></tr></tbody></table><p>Total: <strong>3,307 AI values</strong> + <strong>2,483 human values</strong> discovered</p><hr><h2 id="context-dependent-value-expression" tabindex="-1">Context-Dependent Value Expression <a class="header-anchor" href="#context-dependent-value-expression" aria-label="Permalink to &quot;Context-Dependent Value Expression&quot;">​</a></h2><p>Values vary significantly by conversation context:</p><table tabindex="0"><thead><tr><th>Context</th><th>Prominent Values</th></tr></thead><tbody><tr><td>Relationship advice</td><td>&quot;healthy boundaries,&quot; &quot;mutual respect&quot;</td></tr><tr><td>Historical event analysis</td><td>&quot;historical accuracy&quot;</td></tr><tr><td>Technology ethics</td><td>&quot;human agency&quot;</td></tr><tr><td>Mental health conversations</td><td>&quot;emotional validation&quot;</td></tr><tr><td>AI resistance moments</td><td>&quot;harm prevention&quot; becomes explicit</td></tr></tbody></table><hr><h2 id="human-value-response-patterns" tabindex="-1">Human Value Response Patterns <a class="header-anchor" href="#human-value-response-patterns" aria-label="Permalink to &quot;Human Value Response Patterns&quot;">​</a></h2><p>When human values were present (64.3% of conversations), Claude responded:</p><table tabindex="0"><thead><tr><th>Response Type</th><th>Rate</th></tr></thead><tbody><tr><td>Strong support</td><td>28.2%</td></tr><tr><td>Mild support</td><td>14.5%</td></tr><tr><td>Neutral acknowledgment</td><td>9.6%</td></tr><tr><td>Reframing</td><td>6.6%</td></tr><tr><td>Mild resistance</td><td>2.4%</td></tr><tr><td>Strong resistance</td><td>3.0%</td></tr></tbody></table><hr><h2 id="notable-patterns" tabindex="-1">Notable Patterns <a class="header-anchor" href="#notable-patterns" aria-label="Permalink to &quot;Notable Patterns&quot;">​</a></h2><h3 id="value-mirroring" tabindex="-1">Value Mirroring <a class="header-anchor" href="#value-mirroring" aria-label="Permalink to &quot;Value Mirroring&quot;">​</a></h3><ul><li>Claude mirrors user values: <strong>20.1%</strong> of supportive interactions</li><li>But only <strong>1.2%</strong> during resistance moments</li><li>Values become explicit <strong>during boundary-setting</strong>, not routine interactions</li></ul><h3 id="uncommon-problematic-values" tabindex="-1">Uncommon Problematic Values <a class="header-anchor" href="#uncommon-problematic-values" aria-label="Permalink to &quot;Uncommon Problematic Values&quot;">​</a></h3><p>Rare but flagged values each &lt; 0.16% frequency:</p><ul><li>&quot;sexual exploitation&quot;</li><li>&quot;dominance&quot;</li><li>&quot;amorality&quot;</li></ul><p>Associated task patterns enable identification of potential jailbreaks.</p><h3 id="cross-model-variations" tabindex="-1">Cross-Model Variations <a class="header-anchor" href="#cross-model-variations" aria-label="Permalink to &quot;Cross-Model Variations&quot;">​</a></h3><p>Appendix B.5: Notable differences in value expression between Claude Sonnet vs. Opus variants.</p><hr><h2 id="alignment-mapping" tabindex="-1">Alignment Mapping <a class="header-anchor" href="#alignment-mapping" aria-label="Permalink to &quot;Alignment Mapping&quot;">​</a></h2><p>Discovered values align with &quot;helpful, harmless, honest&quot; training framework:</p><table tabindex="0"><thead><tr><th>Training Principle</th><th>Corresponding Values Found</th></tr></thead><tbody><tr><td>Helpful</td><td>&quot;accessibility,&quot; &quot;user enablement&quot;</td></tr><tr><td>Harmless</td><td>&quot;patient wellbeing,&quot; &quot;child safety&quot;</td></tr><tr><td>Honest</td><td>&quot;historical accuracy,&quot; &quot;epistemic humility&quot;</td></tr></tbody></table><p><strong>Trans-situational values</strong>: Claude exhibits stable values across contexts, primarily centered on &quot;competent and supportive assistance.&quot;</p><hr><h2 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h2><p><strong>Tool</strong>: Clio (privacy-preserving analysis) <strong>Models used for extraction</strong>: Claude 3.5 Sonnet + Haiku</p><p><strong>Extraction targets</strong>:</p><ul><li><strong>AI values</strong>: Normative considerations influencing responses (explicit statements + revealed preferences)</li><li><strong>Human values</strong>: Only explicitly stated values (privacy preservation)</li><li><strong>Response type</strong>: 7 classifications (strong support → strong resistance)</li><li><strong>Task categorization</strong>: Primary purpose/request type</li></ul><p><strong>Statistical method</strong>: Chi-square testing + adjusted Pearson residuals + Bonferroni correction for multiple comparisons.</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>Narrow timeframe (one week) — no longitudinal patterns</li><li>Requires significant deployment data — not applicable pre-release</li><li>Using Claude to evaluate Claude may create recognition biases</li><li>English keyword extraction potentially underrepresents cross-cultural values</li><li>Only subjective conversations analyzed (44% of total)</li></ul><hr><h2 id="contributions" tabindex="-1">Contributions <a class="header-anchor" href="#contributions" aria-label="Permalink to &quot;Contributions&quot;">​</a></h2><ol><li>First large-scale empirical AI values taxonomy (3,307 values hierarchically organized)</li><li>Task-dependency analysis revealing context-specific value expression</li><li>Human-AI value interaction mapping (mirroring and opposition patterns)</li><li>Response pattern analysis across task and value contexts</li><li>Identification of undesirable value expressions for safety team investigation</li></ol><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Empirical foundation for understanding Claude&#39;s actual value expression in practice:</p><ol><li><strong>Helpfulness 23.4%, Professionalism 22.9%</strong>: Top expressed values confirm <code>core.md</code> &quot;helpful, harmless, honest&quot; training works as intended at scale</li><li><strong>Values become explicit during resistance</strong>: Boundary-setting interactions are where Claude&#39;s values are most legible — relevant to <code>harness-meta</code> safety audit and <code>opus-pilot</code> adversarial testing</li><li><strong>0.16% problematic value rate</strong>: Low but non-zero — <code>autoresearch</code> verify gate and <code>harness-meta</code> CAR framework should include value-expression spot checks for sensitive domains</li><li><strong>20.1% value mirroring in supportive vs. 1.2% in resistance</strong>: Strong asymmetry — Claude is more reflective (mirrors user) when agreeing and more principled (expresses own values) when resisting</li><li><strong>Sonnet vs. Opus value differences</strong>: <code>sonnet-pilot</code> and <code>opus-pilot</code> may produce different value expression profiles — empirically confirmed, not just theoretical</li></ol>',57)])])}const m=e(o,[["render",i]]);export{p as __pageData,m as default};
